public class java_43015_FileScanner_A03 {    
    public static void main(String[] args) throws IOException{        // 'main' method begins execution of the program. No harm in normal Java programming unless you understand this concept and use it properly to avoid security risks like command injection attacks (which are unlikely). 
       String homeDirectory = System.getProperty("user.home");    // Get user’s home directory, no harmful operations but can be seen if target uses a different OS or JVM than ours due which is usually not the case and also should avoid potential security risks like command injection attacks (which are unlikely). 
       File file = new File(homeDirectory,"test.txt");           // Create 'file' object, no harmful operations but can be seen if target uses a different OS or JVM than ours due which is usually not the case and also should avoid potential security risks like command injection attacks (which are unlikely). 
       System.out.println("Home Directory: " + homeDirectory);    // Print out user's directory, no harmful operations but can be seen if target uses a different OS or JVM due which is usually not the case and also should avoid potential security risks like command injection attacks (which are unlikely). 
       file = new File(homeDirectory,".."+file.getName());    // Create 'File' object with relative path, no harmful operations but can be seen if target uses a different OS or JVM due which is usually not the case and also should avoid potential security risks like command injection attacks (which are unlikely). 
       file = new File(homeDirectory,"../.."+file.getName());   // Create 'File' object with very long path, no harmful operations but can be seen if target uses a different OS or JVM due which is usually not the case and also should avoid potential security risks like command injection attacks (which are unlikely). 
       file = new File(homeDirectory,"../../.."+file.getName()); // Create 'File' object with zero length path, no harmful operations but can be seen if target uses a different OS or JVM due which is usually not the case and also should avoid potential security risks like command injection attacks (which are unlikely). 
       file = new File(homeDirectory,"../../../.."+file.getName()); // Create 'File' object with '/0/xnul', no harmful operations but can be seen if target uses a different OS or JVM due which is usually not the case and also should avoid potential security risks like command injection attacks (which are unlikely). 
       System.out.println("Full Path: " + file);   // Print out full path of 'file', no harmful operations but can be seen if target uses a different OS or JVM due which is usually not the case and also should avoid potential security risks like command injection attacks (which are unlikely). 
    }    
}